VALUES
  ('diplomatic-9e854390-moex-00596', 'diplomatic-9e854390', 'diplomatic-9e854390-moex-110-4dccc0e6', 'sub-diplomatic-9e854390-04', NULL, 'single_choice', '如欲矯正傳統層級節制的管理方式，對組織內人際互動關係的扭曲、對溝通所形成的障礙、對決 策過程的誤導等，可以透過學習型組織的那一項修練來進行？', '["系統思維", "改善心智模式", "建立共享遠景", "自持自勵、超越自我"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:22:32+00:00", "source_pdf_sha1": "522a4ee8e312", "answer_pdf_sha1": "2e75fe4c2425", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "201", "s": "0406", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政學概要", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 21, "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交行政人員-行政組"}'::jsonb, NULL),
  ('diplomatic-9e854390-moex-00597', 'diplomatic-9e854390', 'diplomatic-9e854390-moex-110-4dccc0e6', 'sub-diplomatic-9e854390-04', NULL, 'single_choice', '下列何者不是建立轉換型領導的行為構成要素？', '["個別關懷", "才能的激發", "相互的影響關係", "權變獎酬"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:22:32+00:00", "source_pdf_sha1": "522a4ee8e312", "answer_pdf_sha1": "2e75fe4c2425", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "201", "s": "0406", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政學概要", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 22, "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交行政人員-行政組"}'::jsonb, NULL),
  ('diplomatic-9e854390-moex-00598', 'diplomatic-9e854390', 'diplomatic-9e854390-moex-110-4dccc0e6', 'sub-diplomatic-9e854390-04', NULL, 'single_choice', '依據我國公務人員行政中立法之規定，下列各項目行為，那一項為公務人員得以從事的項目？', '["加入政黨或其他政治團體", "兼任政黨或其他政治團體之職務", "利用職務上之權力、機會或方法，使他人加入或不加入政黨或其他政治團體", "為支持或反對特定之政黨、其他政治團體，或公職候選人，主持集會、發起遊行或領導連署活動"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:22:32+00:00", "source_pdf_sha1": "522a4ee8e312", "answer_pdf_sha1": "2e75fe4c2425", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "201", "s": "0406", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政學概要", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 23, "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交行政人員-行政組"}'::jsonb, NULL),
  ('diplomatic-9e854390-moex-00599', 'diplomatic-9e854390', 'diplomatic-9e854390-moex-110-4dccc0e6', 'sub-diplomatic-9e854390-04', NULL, 'single_choice', '有關公務員服務法規範的說明，下列何者錯誤？', '["長官就其監督範圍以內所發命令，屬官如有意見，得隨時陳述，但最後屬官仍有服從之義務", "公務員有絕對保守政府機關機密之義務，對於機密事件，除非卸職，否則無論是否主管事務， 均不得洩漏", "公務員非依法不得兼公營事業機關或公司代表官股之董事或監察人", "公務員對於屬官不得推薦人員，並不得就其主管事件有所關說或請託"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:22:32+00:00", "source_pdf_sha1": "522a4ee8e312", "answer_pdf_sha1": "2e75fe4c2425", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "201", "s": "0406", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政學概要", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 24, "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交行政人員-行政組"}'::jsonb, NULL),
  ('diplomatic-9e854390-moex-00600', 'diplomatic-9e854390', 'diplomatic-9e854390-moex-110-4dccc0e6', 'sub-diplomatic-9e854390-04', NULL, 'single_choice', '由非營利組織提供公共服務，近年成為重要的政策現象，請問，以下那一個特質，是非營利組織 能夠持續在社會上存在的原因？', '["非營利組織更有效率及回應性", "非營利組織具有強制的公權力", "非營利組織能夠透過營利，在市場上與私人部門競爭", "非營利組織能夠滿足利他動機"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:22:32+00:00", "source_pdf_sha1": "522a4ee8e312", "answer_pdf_sha1": "2e75fe4c2425", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "201", "s": "0406", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政學概要", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 25, "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交行政人員-行政組"}'::jsonb, NULL),
  ('diplomatic-a3078d07-moex-00001', 'diplomatic-a3078d07', 'diplomatic-a3078d07-moex-114-13504c0c', 'sub-diplomatic-a3078d07-01', NULL, 'single_choice', '下列情境語句，何者用法最為恰當？', '["新居落成：「屋上建瓴，恭喜新居落成。」", "活動開幕：「感謝各位的蒞臨，讓這次的展覽可以厚往薄來。」", "榮退餐會：「恭喜您可以自在逍遙，從今以後可以快意恩仇了。」", "婚禮祝賀：「在這兩家合婚的大好日子，要祝福新人喜結良緣、花好月圓。」"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:25:28+00:00", "source_pdf_sha1": "3403830e86e7", "answer_pdf_sha1": "dbb86ff29ebd", "source_family": "moex-gov-tw", "moex": {"exam_code": "114140", "c": "104", "s": "0101", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "國文(作文與測驗)", "year": "114", "exam_name": "114年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 1, "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交領事人員-印尼文組"}'::jsonb, NULL),
  ('diplomatic-a3078d07-moex-00002', 'diplomatic-a3078d07', 'diplomatic-a3078d07-moex-114-13504c0c', 'sub-diplomatic-a3078d07-01', NULL, 'single_choice', '「不要忘記生命才是創作中最重要的一環。在我們對戲劇理論抱持激情的時候，記 得要先對生命抱持激情。對生命敏感，對人好奇，對現行的世界保有批判的態度， 同時擁有廣納包容的胸襟。」 下列敘述，何者最貼近本文意旨？', '["人要正向思考，不能輕言放棄生命", "好的編劇不僅熟知理論，也對生活周遭充滿關注與熱情", "為人當有雅量，不該對別人好奇，凡事包容體諒即是尊重", "教師教導戲劇理論時不能僅照本宣科，也應教學生認真生活"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:25:28+00:00", "source_pdf_sha1": "3403830e86e7", "answer_pdf_sha1": "dbb86ff29ebd", "source_family": "moex-gov-tw", "moex": {"exam_code": "114140", "c": "104", "s": "0101", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "國文(作文與測驗)", "year": "114", "exam_name": "114年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 2, "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交領事人員-印尼文組"}'::jsonb, NULL),
  ('diplomatic-a3078d07-moex-00003', 'diplomatic-a3078d07', 'diplomatic-a3078d07-moex-114-13504c0c', 'sub-diplomatic-a3078d07-01', NULL, 'single_choice', '「歷史從來都有些勢利眼。歷史的一切總要透過『層積堆疊』，經過『集體記憶』的 萃取純化，方才得以逐漸定型。然而，在此『歷史造山運動』過程之中，歷史的光 圈很容易只集中在『歷史時刻』，相對地，『時刻之前』的脈絡面貌，卻常常會被有 意無意地遺忘或改變了。」 最適合用來說明上文的是：', '["人類歷史經過漫長時間累積，是給後世的智慧結晶", "過往的歷史充滿許多偏見，編修史書尤須格外謹慎", "閱讀歷史如果僅集中特定時刻，容易忽略前後脈絡", "歷史是屬於不同族群的集體記憶，應注意地方差異"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:25:28+00:00", "source_pdf_sha1": "3403830e86e7", "answer_pdf_sha1": "dbb86ff29ebd", "source_family": "moex-gov-tw", "moex": {"exam_code": "114140", "c": "104", "s": "0101", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "國文(作文與測驗)", "year": "114", "exam_name": "114年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 3, "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交領事人員-印尼文組"}'::jsonb, NULL),
  ('diplomatic-a3078d07-moex-00004', 'diplomatic-a3078d07', 'diplomatic-a3078d07-moex-114-13504c0c', 'sub-diplomatic-a3078d07-01', NULL, 'single_choice', '「別忘了這是個國際化的時代。到哪裡都看得到同樣的連鎖速食店、同樣的二十四 小時便利商店、同樣的好萊塢電影海報。完全陌生的角落正逐漸從這個世界上消失。 在這樣的時代我們怎麼可能還有完全的流浪？像馬可波羅、哥倫布那樣，踏上一塊 完全沒有線索可循的土地，連送信回家的信差都沒有，在我們這個時代已經越來越 像則神話。在這個所有角落越來越像的世界裡，怎麼可能還有完全的流浪？」 下列說明，最切近上文主旨的是：', '["人們渴望流浪的感覺", "最好的旅行是如同探險家一般地發現新世界", "世界趨向高度同質化，因此人們認識在地就等於認識了全世界", "全球化之下，各地過多的文化複製空間所帶來的熟悉感，將影響人們的旅行經驗"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:25:28+00:00", "source_pdf_sha1": "3403830e86e7", "answer_pdf_sha1": "dbb86ff29ebd", "source_family": "moex-gov-tw", "moex": {"exam_code": "114140", "c": "104", "s": "0101", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "國文(作文與測驗)", "year": "114", "exam_name": "114年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 4, "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交領事人員-印尼文組"}'::jsonb, NULL),
  ('diplomatic-a3078d07-moex-00005', 'diplomatic-a3078d07', 'diplomatic-a3078d07-moex-114-13504c0c', 'sub-diplomatic-a3078d07-01', NULL, 'single_choice', '「攝影者開始發現自然界的詩意後便停不下來，畢竟捕捉動物一瞬間運動狀態的不 只是機械，還是心靈。美的喚醒如此獨特，以至於同樣一台機械交給不同的人將獲 致不同的結果，而同樣一張照片帶給觀看者的情緒震動，也絕對不是那些一開始希 望相機為科學理性服務的人所能理解的。」 下列選項，何者最不符合上文旨意？', '["相機產生有意義的畫面，是因攝影者使用的機械不同", "照片凝止自然界的運動，使觀看者更能體會自然之美", "照片讓觀看者情緒震動，因相機能捕捉動物瞬間樣態", "影像在藝術與科學間飛翔，透過心靈喚醒自然界之美"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:25:28+00:00", "source_pdf_sha1": "3403830e86e7", "answer_pdf_sha1": "dbb86ff29ebd", "source_family": "moex-gov-tw", "moex": {"exam_code": "114140", "c": "104", "s": "0101", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "國文(作文與測驗)", "year": "114", "exam_name": "114年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交領事人員-印尼文組"}'::jsonb, NULL)
